final:
module top_module (
    input w,
    input g,
    input i,
    input h,
    output reg ee
);
    always @(*) begin
        case ({w, g, i, h})
            4'b1111: ee = 1'b0;
            4'b1110: ee = 1'b0;
            4'b0010: ee = 1'b1;
            4'b0110: ee = 1'b0;
            4'b0000: ee = 1'b1;
            4'b1001: ee = 1'b0;
            4'b1011: ee = 1'b1;
            4'b1100: ee = 1'b0;
            4'b1000: ee = 1'b1;
            4'b0001: ee = 1'b0;
            4'b0101: ee = 1'b1;
            4'b0111: ee = 1'b0;
            4'b0100: ee = 1'b1;
            4'b0011: ee = 1'b1;
            4'b1010: ee = 1'b1;
            4'b1101: ee = 1'b0;
        endcase
    end
endmodule
